const fmt = n => `$${Number(n || 0).toFixed(2)}`;
const fmtW = n => `${Number(n || 0).toFixed(2)} lbs`;
const today = () => { const d = new Date(); return d.getFullYear() + "-" + String(d.getMonth() + 1).padStart(2, "0") + "-" + String(d.getDate()).padStart(2, "0"); };
const dueDate = (days = 7) => {
  const d = new Date();
  d.setDate(d.getDate() + days);
  return d.getFullYear() + "-" + String(d.getMonth() + 1).padStart(2, "0") + "-" + String(d.getDate()).padStart(2, "0");
};
const TERMS_OPTIONS = ["COD", "Bill to Bill", "1 Week", "2 Weeks", "3 Weeks", "4 Weeks"];
const termsToDays = terms => {
  if (!terms) return 7;
  const t = terms.toLowerCase();
  if (t === "cod") return 0;
  if (t === "bill to bill") return 7; // due following week if customer doesn't buy again
  if (t === "1 week") return 7;
  if (t === "2 weeks") return 14;
  if (t === "3 weeks") return 21;
  if (t === "4 weeks") return 28;
  // Legacy support
  const m = t.match(/net\s*(\d+)/);
  if (m) return Number(m[1]);
  return 7;
};
const dueDateFromTerms = terms => dueDate(termsToDays(terms));
const genId = prefix => `${prefix}-${Date.now().toString().slice(-6)}`;

// Product display name: lowercase when sold by piece, normal case when sold by case
// If line has a customName override, use that instead
const pName = (prod, line) => {
  if (!prod && !(line !== null && line !== void 0 && line.customName)) return (line === null || line === void 0 ? void 0 : line.productId) || "—";
  const baseName = (line === null || line === void 0 ? void 0 : line.customName) || (prod === null || prod === void 0 ? void 0 : prod.name) || "—";
  const unit = (line === null || line === void 0 ? void 0 : line.unit) || "CS";
  return unit === "CS" ? baseName : baseName.toLowerCase();
};

const getCustomerOrderHistory = (custId, salesOrders, invoices) => {
  const hist = {};
  const allDocs = [
    ...(salesOrders || []).filter(so => so.customerId === custId && so.status !== "cancelled"),
    ...(invoices || []).filter(inv => inv.customerId === custId && inv.status !== "voided")
  ];
  allDocs.forEach(doc => {
    (doc.lines || []).forEach(l => {
      const pid = l.productId;
      if (!pid) return;
      const qty = Number(l.qty || l.qtyOrdered || l.qtyShipped) || 0;
      if (qty <= 0) return;
      if (!hist[pid]) hist[pid] = { count: 0, totalQty: 0, lastDate: null, dates: [] };
      hist[pid].count++;
      hist[pid].totalQty += qty;
      const d = doc.date || doc.deliveryDate;
      if (d) {
        hist[pid].dates.push(d);
        if (!hist[pid].lastDate || d > hist[pid].lastDate) hist[pid].lastDate = d;
      }
    });
  });
  Object.keys(hist).forEach(pid => {
    hist[pid].avgQty = Math.round(hist[pid].totalQty / hist[pid].count * 10) / 10;
  });
  return hist;
};

// ── Global AR Balance Helpers ──
// These are used across multiple modules for consistent balance calculation
const arGetInvPaid = (invId, arPayments) => (arPayments || []).filter(p => p.status !== "void" && p.status !== "returned").reduce((s, p) => s + (p.appliedTo || []).filter(a => a.invoiceId === invId).reduce((ss, a) => ss + a.amount, 0), 0);
const arGetInvCredits = (invId, creditMemos) => (creditMemos || []).filter(cm => cm.invoiceId === invId && cm.status !== "void").reduce((s, cm) => s + (cm.total || 0), 0);
const arGetInvBalance = (inv, arPayments, creditMemos) => Math.round(((inv.total || 0) - arGetInvPaid(inv.id, arPayments) - arGetInvCredits(inv.id, creditMemos)) * 100) / 100;
const arGetCustBalance = (custId, invoices, arPayments, creditMemos) => (invoices || []).filter(i => i.customerId === custId && i.status === "open").reduce((s, i) => s + Math.max(0, arGetInvBalance(i, arPayments, creditMemos)), 0);

// ── DOCUMENT LOCK SYSTEM (cross-tab editing protection) ──
const TAB_ID = `tab_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`;
const LOCK_EXPIRY_MS = 5 * 60 * 1000; // 5 minutes
const LOCK_HEARTBEAT_MS = 30 * 1000; // refresh every 30s

function acquireLock(docType, docId, userName) {
  const key = `ft_lock_${docType}_${docId}`;
  const existing = localStorage.getItem(key);
  if (existing) {
    try {
      const lock = JSON.parse(existing);
      if (lock.tabId !== TAB_ID && Date.now() - lock.timestamp < LOCK_EXPIRY_MS) {
        return {
          success: false,
          holder: lock
        };
      }
    } catch (e) {}
  }
  const lock = {
    tabId: TAB_ID,
    user: userName || "User",
    docId,
    docType,
    timestamp: Date.now()
  };
  localStorage.setItem(key, JSON.stringify(lock));
  return {
    success: true,
    holder: lock
  };
}
function releaseLock(docType, docId) {
  const key = `ft_lock_${docType}_${docId}`;
  const existing = localStorage.getItem(key);
  if (existing) {
    try {
      const lock = JSON.parse(existing);
      if (lock.tabId === TAB_ID) localStorage.removeItem(key);
    } catch (e) {
      localStorage.removeItem(key);
    }
  }
}
function refreshLock(docType, docId) {
  const key = `ft_lock_${docType}_${docId}`;
  const existing = localStorage.getItem(key);
  if (existing) {
    try {
      const lock = JSON.parse(existing);
      if (lock.tabId === TAB_ID) {
        lock.timestamp = Date.now();
        localStorage.setItem(key, JSON.stringify(lock));
      }
    } catch (e) {}
  }
}
function checkLock(docType, docId) {
  const key = `ft_lock_${docType}_${docId}`;
  const existing = localStorage.getItem(key);
  if (!existing) return null;
  try {
    const lock = JSON.parse(existing);
    if (Date.now() - lock.timestamp >= LOCK_EXPIRY_MS) {
      localStorage.removeItem(key);
      return null;
    }
    if (lock.tabId === TAB_ID) return null; // our own lock
    return lock;
  } catch (e) {
    return null;
  }
}

// Cleanup all our locks on tab close
if (typeof window !== "undefined") {
  window.addEventListener("beforeunload", () => {
    for (let i = 0; i < localStorage.length; i++) {
      const k = localStorage.key(i);
      if (k && k.startsWith("ft_lock_")) {
        try {
          const lock = JSON.parse(localStorage.getItem(k));
          if (lock.tabId === TAB_ID) localStorage.removeItem(k);
        } catch (e) {}
      }
    }
  });
}

// Hook: use inside components for lock management
function useLock(docType, docId, isEditing, userName) {
  useEffect(() => {
    if (!isEditing || !docId) return;
    acquireLock(docType, docId, userName);
    const interval = setInterval(() => refreshLock(docType, docId), LOCK_HEARTBEAT_MS);
    return () => {
      clearInterval(interval);
      releaseLock(docType, docId);
    };
  }, [isEditing, docId, docType, userName]);
}

