// DATABASE — Persistent Storage via PostgreSQL API
// ============================================================
const DB_KEY = "freshtrade_db";
const DB_VERSION = "v4_6pin";
const DB_TABLES = ["products", "customers", "invoices", "routes", "salesOrders", "suppliers", "purchaseOrders", "salespeople", "creditMemos", "deliveries", "productionRuns", "receipts", "arPayments", "arDeposits", "settings"];

// Load data from server API
const dbLoadAsync = async () => {
  try {
    const res = await fetch("/api/data");
    if (!res.ok) return null;
    const data = await res.json();
    if (Object.keys(data).length === 0) return null;
    return data;
  } catch (e) {
    console.warn("DB load error:", e);
    return null;
  }
};

// Synchronous wrapper - returns cached data
let _cachedData = null;
const dbLoad = () => _cachedData;

// Save data to server API (debounced)
let _saveTimer = null;
const dbSave = state => {
  if (_saveTimer) clearTimeout(_saveTimer);
  _saveTimer = setTimeout(async () => {
    try {
      const data = {};
      DB_TABLES.forEach(k => {
        data[k] = state[k];
      });
      await fetch("/api/data", {
        method: "PUT",
        headers: {
          "Content-Type": "application/json"
        },
        body: JSON.stringify(data)
      });
    } catch (e) {
      console.warn("DB save error:", e);
    }
  }, 800);
};
const dbExport = state => {
  const data = {
    _v: DB_VERSION,
    _exported: new Date().toISOString(),
    _app: "FreshTrade"
  };
  DB_TABLES.forEach(k => {
    data[k] = state[k];
  });
  const blob = new Blob([JSON.stringify(data, null, 2)], {
    type: "application/json"
  });
  const url = URL.createObjectURL(blob);
  const a = document.createElement("a");
  a.href = url;
  a.download = `FreshTrade_Backup_${new Date().toISOString().split("T")[0]}.json`;
  a.click();
  URL.revokeObjectURL(url);
};
const dbClear = async () => {
  try {
    await fetch("/api/reset", {
      method: "POST"
    });
  } catch (e) {}
};

