    const weight = lineWeight ? Number(lineWeight) : null;
    const total = prod.catchWeight && weight ? weight * price : Number(lineQty) * price;
    setForm(f => ({
      ...f,
      lines: [...f.lines, {
        productId: prod.id,
        qty: Number(lineQty),
        weight,
        pricePerLb: prod.catchWeight ? price : undefined,
        priceEach: !prod.catchWeight ? price : undefined,
        total
      }]
    }));
    setLineProduct("");
    setLineQty("");
